+export async function readJsonFile<T = unknown>(
+	filePath: string,
+): Promise<T | undefined> {
+	try {
+		const content = await fs.readFile(filePath, "utf8");
+		return JSON.parse(content) as T;
+	} catch (error) {
+		if ((error as NodeJS.ErrnoException).code === "ENOENT") {
+			return undefined;
+		}
+		throw error;
+	}
+}
