+export async function writeJsonFile(
+	filePath: string,
+	data: unknown,
+): Promise<void> {
+	await fs.mkdir(path.dirname(filePath), { recursive: true });
+	await fs.writeFile(filePath, JSON.stringify(data, null, 2), "utf8");
